const body = $input.first().json.body || $input.first().json;
const text = (body.text || '').trim();
const userLat = parseFloat(body.lat) || 37.5665;
const userLng = parseFloat(body.lng) || 126.9780;
const userTransportMode = body.transportMode || 'transit';
const categoryGroupCode = (body.categoryGroupCode || '').trim();

let q = text;
q = q.replace(/근처\s*/g, '').trim();
q = q.replace(/(으로|로)\s*(가기|가는\s*길|길찾기|안내|가자|갈래|가고\s*싶어|가줘)/g, '').trim();
q = q.replace(/(에|까지)\s*(가기|가는\s*길|길찾기|안내)/g, '').trim();
q = q.replace(/(찾아줘|찾아주세요|알려줘|알려주세요|가줘)/g, '').trim();

let mode = userTransportMode;
if (/대중교통|버스|지하철|전철|기차|KTX|SRT/.test(text)) mode = 'transit';
else if (/자동차|차로|드라이브|운전|차량|차$|차로/.test(text)) mode = 'car';
q = q.replace(/^(대중교통으로|자동차로|버스로|지하철로|도보로|차로)\s*/g, '').trim();

if (!q) q = text;

// 카카오 API URL 직접 빌드 (빈 category_group_code 거부 문제 회피)
const params = {
  query: q,
  x: userLng,
  y: userLat,
  radius: '5000',
  sort: 'distance',
  size: '10',
};
if (categoryGroupCode) params.category_group_code = categoryGroupCode;
const qs = Object.entries(params).map(([k,v]) => k + '=' + encodeURIComponent(v)).join('&');
const kakaoUrl = 'https://dapi.kakao.com/v2/local/search/keyword.json?' + qs;

return [{
  json: {
    query: q,
    categoryGroupCode,
    transportMode: mode,
    userLat,
    userLng,
    originalText: text,
    kakaoUrl,
  }
}];

const data = $input.first().json;
const input = $('입력 준비').first().json;

const docs = data?.documents || [];
if (!docs.length) {
  return [{ json: { candidates: [], destination: input.query, transportMode: input.transportMode } }];
}

const candidates = docs.map((d, i) => {
  const lat = parseFloat(d.y);
  const lng = parseFloat(d.x);
  const dm = parseInt(d.distance) || 0;
  return {
    index: i + 1,
    name: d.place_name,
    address: d.road_address_name || d.address_name || '',
    category: d.category_group_name || (d.category_name || '').split(' > ').pop() || '',
    lat, lng,
    distanceM: dm,
    distanceLabel: dm < 1000 ? dm + 'm' : (dm / 1000).toFixed(1) + 'km',
    phone: d.phone || '',
    placeUrl: d.place_url || '',
  };
});

return [{ json: { candidates, destination: input.query, transportMode: input.transportMode } }];
